import { useState } from 'react';
import { Link, NavLink, useNavigate } from 'react-router-dom';

import constFlaskURL from '../../consts/constFlaskURL'

import '../../App.css';
import '../../../node_modules/bootstrap/dist/css/bootstrap.css'


function AddSing() {
    const [form, setForm] = useState({ name_sing: '' });
    const [loading, setLoading] = useState(false);
    const navigate = useNavigate();

    const handleLogout = async () => {
        setLoading(true);

        try 
        {
            const response = await constFlaskURL.post('/logout');

            if (response.status === 200) 
            {
                setTimeout(() => {
                    navigate('/login');
                }, 1000);
            }
        }
        catch (err) 
        {
            console.error('Logout error:', err);
        } 
        finally 
        {
            setLoading(false);
        }
    };

    const submitSing = async (e) => {
        e.preventDefault();

        try {
            const add_sing = await constFlaskURL.post('/sings', {
                name_sing: form.name_sing
            });

            if (add_sing.status === 201){
                setForm('');
                navigate('/sings');
            }

        } catch (error) {
            console.log(error);
        }
    };

    return (
        <div>
            <nav className="navbar navbar-expand-lg navbar-dark bg-dark flex-column align-items-start p-0">
                <div className="container-fluid py-2">
                    <Link className="navbar-brand fs-3 fw-bold" to="/main">roads_admin</Link>
                    <Link className="navbar-brand fs-3 fw-bold">
                        <button 
                            onClick={handleLogout} 
                                className="logout-button"
                                disabled={loading}
                            >
                            {loading ? (
                            <>
                                <span className="spinner"></span>
                                Выход...
                            </>
                            ) : 'Выйти'}
                        </button>
                    </Link>
                </div>
            </nav>
            <form className='container' onSubmit={submitSing}>
                <div className='mb-3'>
                    <lable className='form-label'>Название дорожного знака</lable>
                    <input value={name_sing} onChange={(e) => setForm(e.target.value)} type='text' placeholder='Название дорожного знака' className='form-control' />
                </div>
                <button type='submit' className='btn btn-primary'>
                    Создать запись
                </button>
            </form>
        </div>
    )

};

export default AddSing;
